import React, { useState } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshMovements, updateProductQuantity }) => {
    const [produtoId, setProdutoId] = useState('');
    const [tipoMovimentacao, setTipoMovimentacao] = useState('entrada');
    const [quantidade, setQuantidade] = useState('');
    const [motivo, setMotivo] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await axios.post('http://127.0.0.1:8000/api/movimentacoes/', {
                produto: produtoId,
                tipo_movimentacao: tipoMovimentacao,
                quantidade: quantidade,
                motivo: motivo,
            });

            // Atualiza a quantidade do produto
            updateProductQuantity(produtoId, tipoMovimentacao, parseInt(quantidade));

            // Limpa os campos do formulário
            setProdutoId('');
            setTipoMovimentacao('entrada');
            setQuantidade('');
            setMotivo('');

            refreshMovements(); // Atualiza as movimentações
        } catch (error) {
            console.error("Erro ao registrar movimentação:", error);
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <select value={produtoId} onChange={(e) => setProdutoId(e.target.value)} required>
                <option value="">Selecione um produto</option>
                {/* Aqui você deve mapear os produtos disponíveis */}
                {/* {products.map((product) => (
                    <option key={product.id} value={product.id}>
                        {product.nome}
                    </option>
                ))} */}
            </select>
            <select value={tipoMovimentacao} onChange={(e) => setTipoMovimentacao(e.target.value)}>
                <option value="entrada">Entrada</option>
                <option value="saida">Saída</option>
            </select>
            <input
                type="number"
                value={quantidade}
                onChange={(e) => setQuantidade(e.target.value)}
                placeholder="Quantidade"
                required
            />
            <textarea
                value={motivo}
                onChange={(e) => setMotivo(e.target.value)}
                placeholder="Motivo"
            />
            <button type="submit">Registrar Movimentação</button>
        </form>
    );
};

export default StockMovementForm;
